content.query:
Tailscale_Audit_CL
| where TimeGenerated {TimeRange}
| summarize TotalEvents = count(), UniqueActors = dcount(tostring(Actor.loginName)), ACLChanges = countif(Action == "UPDATE" and tostring(Target.type) == "TAILNET" and tostring(Target.property) == "ACL"), CredentialsCreated = countif(Action == "CREATE" and tostring(Target.type) in ("AUTH_KEY", "API_KEY", "OAUTH_CLIENT"))

Tailscale_Network_CL
| where TimeGenerated {TimeRange}
| summarize Messages = count(), UniqueNodes = dcount(NodeId)
